1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type Step = { op: "quote"; items: Item[] };
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
16	
17	const quotePremium = (items: Item[]): number => {
18	  const policyBase = items.reduce((sum, item) => sum + basePremium(item), 0);
19	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
20	  return Math.ceil(policyBase + firstInsuranceSurcharge) + PROCESSING_FEE;
21	};
22	
23	export const runScenario = (input: unknown): unknown => {
24	  const scenario = input as Scenario;
25	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
26	  return { results };
27	};
